import React, { useEffect, useState } from 'react';
import { Link, useParams } from 'react-router-dom';
import toast from 'react-hot-toast';
import { nguoiDungAPI } from '../services/api';
import useAuthStore from '../store/authStore';
import './TrangCaNhanCongKhai.css';

const formatDate = value => (value ? new Date(value).toLocaleDateString('vi-VN') : 'Chua cap nhat');

export default function TrangCaNhanCongKhai() {
  const { id } = useParams();
  const { user } = useAuthStore();
  const [profile, setProfile] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let active = true;

    setLoading(true);
    nguoiDungAPI.layTrangCaNhanCongKhai(id)
      .then(res => {
        if (active) {
          setProfile(res.data.data);
        }
      })
      .catch(() => {
        if (active) {
          setProfile(null);
          toast.error('Khong tim thay trang ca nhan');
        }
      })
      .finally(() => {
        if (active) {
          setLoading(false);
        }
      });

    return () => {
      active = false;
    };
  }, [id]);

  if (loading) return <div className="spinner" />;
  if (!profile) {
    return (
      <div className="container page-wrapper">
        <div className="alert alert-danger">Khong tim thay trang ca nhan nay.</div>
      </div>
    );
  }

  const isOwner = user?.maNguoiDung === profile.maNguoiDung;
  const reviews = profile.danhGiaNhanDuoc || [];

  return (
    <div className="container page-wrapper">
      <div className="public-profile-hero card">
        <div className="card-body public-profile-hero-body">
          <img
            src={profile.avatar || `https://ui-avatars.com/api/?name=${encodeURIComponent(profile.hoTen || 'User')}&background=12355B&color=fff&size=160`}
            alt={profile.hoTen}
            className="avatar avatar-xl public-profile-avatar"
          />

          <div className="public-profile-main">
            <div className="public-profile-title-row">
              <h1>{profile.hoTen}</h1>
              {profile.xacThuc && <span className="badge badge-success">Da xac thuc CCCD</span>}
            </div>

            <p className="public-profile-subtitle">
              Trang ca nhan cong khai de nguoi khac xem thong tin co ban, do uy tin va danh gia nhan duoc.
            </p>

            <div className="public-profile-meta">
              <span>Tham gia tu {formatDate(profile.ngayTao)}</span>
              <span>{profile.diemDanhGia ? `${profile.diemDanhGia.toFixed(1)} / 5 sao` : 'Chua co danh gia'}</span>
            </div>

            <div className="public-profile-actions">
              {isOwner ? (
                <>
                  <Link to="/ho-so" className="btn btn-primary">Chinh sua ho so cua toi</Link>
                  <span className="public-profile-owner-note">Chi ban moi sua duoc thong tin tren trang nay.</span>
                </>
              ) : (
                <span className="public-profile-owner-note">Day la trang cong khai cua thanh vien nay.</span>
              )}
            </div>
          </div>
        </div>
      </div>

      <div className="grid-3 public-profile-stats">
        <div className="stat-card">
          <div className="stat-value">{profile.tongBaiDang || 0}</div>
          <div className="stat-label">Bai dang da tao</div>
        </div>
        <div className="stat-card">
          <div className="stat-value">{profile.tongPhong || 0}</div>
          <div className="stat-label">Phong dang quan ly</div>
        </div>
        <div className="stat-card">
          <div className="stat-value">{profile.diemDanhGia ? profile.diemDanhGia.toFixed(1) : '0.0'}</div>
          <div className="stat-label">Do uy tin hien tai</div>
        </div>
      </div>

      <div className="grid-2 public-profile-layout">
        <div className="card">
          <div className="card-header">Thong tin cong khai</div>
          <div className="card-body">
            <div className="info-row">
              <span>Ho ten</span>
              <strong>{profile.hoTen}</strong>
            </div>
            <div className="info-row">
              <span>Tinh trang xac thuc</span>
              <strong>{profile.xacThuc ? 'Da xac thuc CCCD' : 'Chua xac thuc'}</strong>
            </div>
            <div className="info-row">
              <span>Ngay tham gia</span>
              <strong>{formatDate(profile.ngayTao)}</strong>
            </div>
            <div className="info-row">
              <span>Danh gia trung binh</span>
              <strong>{profile.diemDanhGia ? `${profile.diemDanhGia.toFixed(1)} / 5` : 'Chua co'}</strong>
            </div>
          </div>
        </div>

        <div className="card">
          <div className="card-header">Danh gia nhan duoc</div>
          <div className="card-body">
            {reviews.length === 0 ? (
              <div className="review-empty">
                Thanh vien nay chua nhan duoc danh gia cong khai nao.
              </div>
            ) : (
              <div className="review-list">
                {reviews.map(review => (
                  <div key={review.maDanhGia} className="review-item">
                    <div className="review-top">
                      <Link to={`/nguoi-dung/${review.maNguoiDanhGia}`} className="public-profile-reviewer">
                        <img
                          src={review.avatarNguoiDanhGia || `https://ui-avatars.com/api/?name=${encodeURIComponent(review.tenNguoiDanhGia || 'U')}&background=12355B&color=fff&size=40`}
                          alt={review.tenNguoiDanhGia}
                          className="avatar avatar-sm"
                        />
                        <strong>{review.tenNguoiDanhGia || 'Nguoi dung an danh'}</strong>
                      </Link>
                      <span className="stars">{'★'.repeat(review.soSao || 0)}{'☆'.repeat(5 - (review.soSao || 0))}</span>
                    </div>
                    <div className="public-profile-review-content">
                      {review.moTa || 'Khong co nhan xet chi tiet'}
                    </div>
                    <div className="review-date">{formatDate(review.ngayDanhGia)}</div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}
